python3 - <<'PY'
import json, math, glob, os
from collections import defaultdict
import numpy as np
SRC='/source/phase_segment_9_phase_0'

def load_jsonl(path):
    with open(path) as f:
        return [json.loads(l) for l in f if l.strip()]

# SDF benchmark raw recomputation (fact-level mean then mean over facts)
low_verif={json.loads(l)['id'] for l in open(f'{SRC}/data/sdf_eval_facts.jsonl') if json.loads(l).get('verifiability')=='low'}
files={
 'base':f'{SRC}/results/baseline_sdfbench_base_feb3061.jsonl',
 'PFF':f'{SRC}/results/baseline_sdfbench_pff_feb3061.jsonl',
 'SDF':f'{SRC}/results/sdf_eval_3k_main.jsonl'
}
arm_filter={'base':lambda r:r.get('channel')=='facts_tags','PFF':lambda r:r.get('channel')=='facts_tags','SDF':lambda r:r.get('channel')=='no_injection'}
metrics={'direct':['direct'],'truth_discrimination':['distinguish'],'downstream':['probe'],'multiple_choice':['mc']}
print('SDF benchmark recomputed from JSONL (mean of fact means):')
for arm,path in files.items():
    rows=[r for r in load_jsonl(path) if arm_filter[arm](r) and not r.get('truncated')]
    vals={}
    for m,etypes in metrics.items():
        by=defaultdict(list)
        for r in rows:
            if r.get('etype') not in etypes: continue
            # exclude parse errors for grader based direct/probe
            if r.get('etype') in ('direct','probe') and isinstance(r.get('grader'),dict) and r['grader'].get('_parse_error'): continue
            if r.get('etype')=='distinguish' and r.get('fact_id') in low_verif: continue
            b=r.get('belief')
            if b is not None and not (isinstance(b,float) and math.isnan(b)): by[r['fact_id']].append(float(b))
        vals[m]=sum(np.mean(v) for v in by.values())/len(by) if by else float('nan')
    print(arm, {k:round(v,3) for k,v in vals.items()})

# S6 plateau raw summary from cross technique
ct=json.load(open(f'{SRC}/results/cross_technique.json'))
print('\nS6 plateau force means:', {k:round(ct['agentic_scrutiny_s6_plateau'][k]['force']['mean'],3) for k in ['base_facts','PFF_facts','PFF_facts_plus_cot']})

# Audit search summary raw
summ=json.load(open(f'{SRC}/results/audit_summary.json'))
print('\nAudit search summary:', {k:summ[k] for k in ['N_searched','n_facts','n_tasks','K_flagged']})
print('Flagged >=0.4 count', len(summ['flagged']))

# Fidelity / fabrication workflow
fw=json.load(open(f'{SRC}/results/fab_workflow.json'))
print('\nFabrication workflow base valid rates:')
for key in fw:
    if key.startswith('citation'):
        print(key.split('|')[1].strip(), 'base valid', round(fw[key]['base']['valid'],3), 'belief', fw[key]['base']['belief'], 'trunc', round(fw[key]['base']['trunc'],3), 'imputed', fw[key].get('base_imputed'))
print('\nMarket workflow base valid rates:')
for key in fw:
    if key.startswith('market'):
        print(key.split('|')[1].strip(), 'base valid', round(fw[key]['base']['valid'],3), 'belief', fw[key]['base']['belief'], 'trunc', round(fw[key]['base']['trunc'],3), 'imputed', fw[key].get('base_imputed'))

# Long horizon base action rates, PFF positives
lh=json.load(open(f'{SRC}/results/longhorizon_analysis.json'))
print('\nLong-horizon key cells:')
for fid in ['lh_db_migration','lh_wrong_send']:
    for h in [0,20,40,29]:
        key=f'{fid}|realistic|{h}|base'
        if key in lh: print(key, 'base action', lh[key]['mis'], 'gated', lh[key]['rf_gated'], 'notgated', lh[key]['rf_notgated'], 'missed', lh[key]['rf_missed'], 'trunc', round(lh[key]['trunc'],2))
    for key in sorted(k for k in lh if k.startswith(fid+'|facts_long') and k.endswith('|pff')):
        print(key, 'PFF facts_long action', lh[key]['mis'])
    key=f'{fid}|facts|-1|pff'
    if key in lh: print(key, 'PFF facts single action', lh[key]['mis'])

# Costs
cost=json.load(open(f'{SRC}/results/sdf_cost.json'))
print('\nCosts:', {k:cost[k] for k in ['sdf_marginal_per_fact_usd','sdf_per_fact_usd','pff_marginal_per_fact_usd','pff_dev_onetime_usd','breakeven_facts_vs_dev_cost']})
